import 'package:flutter/services.dart' show rootBundle;
import 'dart:convert';
import 'package:http/http.dart' as http;

const String apiUrl = "https://api.example.com";
String accessToken; // This should be obtained during authentication

Future<void> initialize() async {
  String jsonWithToken = await rootBundle.loadString('assets/token.json');
  Map<String, dynamic> tokenData = jsonDecode(jsonWithToken);
  accessToken = tokenData['access_token'];
}

Future<http.Response> getUserProfile() {
  return http.get(Uri.parse("$apiUrl/user-profile"), headers: {'Authorization': 'Bearer $accessToken'});
}

// Assume that data is a JSON object representing data to be synced.
Future<void> syncData(Map<String, dynamic> data) {
  return http.put(Uri.parse("$apiUrl/sync-data"), body: jsonEncode(data), headers: {'Authorization': 'Bearer $accessToken'});
}